def lcs_length(a, b):
    # compute LCS length using DP; careful with length
    # We'll compute per character; both are not too long
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev = 0
        for j in range(1,m+1):
            tmp = dp[j]
            if a[i-1]==b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = tmp
    return dp[m]

def lcs_ratio(a, b):
    l = lcs_length(a, b)
    return l / max(1, (len(a) + len(b) - l))

def token_f1(a, b):
    ta = a.split()
    tb = b.split()
    ca = Counter(ta)
    cb = Counter(tb)
    inter = sum((ca & cb).values())
    prec = inter / max(1, sum(ca.values()))
    rec = inter / max(1, sum(cb.values()))
    if prec + rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

